require "prefabutil" local assets = {Asset( "ANIM" , "anim/wilsonstatue.zip" ), Asset( "MINIMAP_IMAGE" , "resurrect" ),} local function onhammered(inst, worker) SpawnPrefab( "collapse_big" ).Transform:SetPosition(inst.Transform:GetWorldPosition()) inst.SoundEmitter:PlaySound( "dontstarve/common/destroy_wood" ) inst:Remove() end local function onhit(inst) inst.healTimer = 0x0 inst.AnimState:PlayAnimation( "hit" ) inst.AnimState:PushAnimation( "idle" ) end local function onwork(inst, worker, workleft) local hashammer = false if worker.components.inventory then for k, v in pairs(worker.components.inventory.equipslots) do if v.components.tool and v.components.tool:CanDoAction(ACTIONS.HAMMER) then hashammer = true if v.components.finiteuses then v.components.finiteuses:Use( - 0x1) end break end end end if not hashammer then inst.components.workable.destroyed = false inst.components.workable.workleft = inst.workleft else inst.workleft = inst.workleft - 0x1 inst.components.workable.workleft = inst.workleft end onhit(inst) end local function onattacked(inst, attacker, damage) onhit(inst) end local function onhealthchange(inst, old_percent, new_percent) if new_percent <= 0x0 then inst.components.health.currenthealth = inst.components.health.maxhealth * old_percent new_percent = old_percent end end local function onload(inst, data) inst.workleft = inst.components.workable.workleft end function onburnt(inst) local ash = SpawnPrefab( "ash" ) ash.Transform:SetPosition(inst.Transform:GetWorldPosition()) inst.AnimState:SetMultColour(0x1, 0x1, 0x1, 0x1) end local function fn(Sim) local inst = CreateEntity() inst.entity:AddTransform() inst.entity:AddAnimState() inst.entity:AddMiniMapEntity() inst.entity:AddSoundEmitter() MakeObstaclePhysics(inst,.3) inst.MiniMapEntity:SetIcon( "resurrect.png" ) inst:AddTag( "structure" ) inst.AnimState:SetBank( "wilsonstatue" ) inst.AnimState:SetBuild( "wilsonstatue" ) inst.AnimState:PlayAnimation( "idle" ) inst:AddComponent( "inspectable" ) inst:AddComponent( "lootdropper" ) inst:AddComponent( "combat" ) inst.components.combat.onhitfn = onattacked local hp = 0x3e8 inst:AddComponent( "health" ) inst.components.health:SetMaxHealth(hp) inst.components.health.currenthealth = hp inst.components.health.ondelta = onhealthchange inst.components.health.nofadeout = true inst.components.health.canheal = false inst:AddTag( "noauradamage" ) inst:AddComponent( "workable" ) inst.components.workable:SetWorkAction(ACTIONS.HAMMER) inst.components.workable:SetWorkLeft(0x4) inst.components.workable:SetOnFinishCallback(onhammered) inst.components.workable:SetOnWorkCallback(onwork) inst.workleft = 0x4 MakeSnowCovered(inst,.01) MakeLargeFreezableCharacter(inst) MakeLargeBurnable(inst) inst.components.burnable:SetOnBurntFn(onburnt) inst.OnLoad = onload inst.healTimer = 0x0 inst:DoPeriodicTask(FRAMES, function() inst.healTimer = inst.healTimer + FRAMES if inst.healTimer >= 0x5 and inst.components.health.currenthealth < hp then inst.healTimer = 0x0 inst.components.health:DoDelta(hp, false, "regen" ) end end) return inst end return Prefab( "common/objects/dyc_damagetesttarget" , fn, assets) 